module RefModule (
    input A,
    input B,
    input CI,
    output SUM,
    output COUT
);

    wire obf_xor1_out;
    wire xor2_out;
    wire and1_out;
    wire and2_out;
    wire or1_out;

    xor xor1(obf_xor1_out, A, B);
    xor xor2(SUM, obf_xor1_out, CI);
    and and1(and1_out, A, B);
    and and2(and2_out, obf_xor1_out, CI);
    or or1(or1_out, and1_out, and2_out);
    assign COUT = or1_out;

endmodule
